    fn dict_row(content_type: &str, role: &str, concept: &str, label: &str) -> DictRow {
        DictRow {
            content_type: content_type.to_string(),
            role: role.to_string(),
            concept: concept.to_string(),
            label: label.to_string(),
            ..Default::default()
        }
    }

    #[test]
    fn route_from_concept_maps_namespaces() {
        // coordinates -> map; other geo keys (census_tract, zip, ...) -> dimension bar
        assert_eq!(
            route_from_concept("geo.latitude"),
            Some((Route::MapCoord, None))
        );
        assert_eq!(
            route_from_concept("geo.coordinate_pair"),
            Some((Route::MapCoord, None))
        );
        assert_eq!(
            route_from_concept("geo.census_tract"),
            Some((Route::Dimension, None))
        );
        // state-plane planar coordinates: neither mappable nor a place key -> ProjectedCoord,
        // which charts a distribution only when no point map rendered (see
        // `classify_with_semantics_routes`)
        assert_eq!(
            route_from_concept("geo.crs_stateplane_x"),
            Some((Route::ProjectedCoord, None))
        );
        assert_eq!(
            route_from_concept("geo.crs_stateplane_y"),
            Some((Route::ProjectedCoord, None))
        );
        assert_eq!(
            route_from_concept("nyc.bbl"),
            Some((Route::Dimension, None))
        );
        // temporal
        assert_eq!(
            route_from_concept("time.created_at"),
            Some((Route::Temporal, None))
        );
        // identifiers / PII -> skip
        assert_eq!(
            route_from_concept("id.surrogate_key"),
            Some((Route::Skip, None))
        );
        assert_eq!(route_from_concept("pii.email"), Some((Route::Skip, None)));
        // measures: amount/count additive (Sum), ratio averaged (Mean)
        assert_eq!(
            route_from_concept("measure.amount"),
            Some((Route::Measure, Some(Agg::Sum)))
        );
        assert_eq!(
            route_from_concept("measure.count"),
            Some((Route::Measure, Some(Agg::Sum)))
        );
        assert_eq!(
            route_from_concept("measure.ratio"),
            Some((Route::Measure, Some(Agg::Mean)))
        );
        // unknown namespace / bare unknown -> None (fall through to role)
        assert_eq!(route_from_concept("weather.temp"), None);
        assert_eq!(route_from_concept("unknown"), None);
    }

    #[test]
    fn intensive_measure_detection() {
        // intensive quantities -> averaged, matched by label or field
        assert!(is_intensive_measure(
            "Average Annual Temperature (\u{b0}C)",
            "avg_annual_temp_c"
        ));
        assert!(is_intensive_measure("Elevation", "elevation_m"));
        assert!(is_intensive_measure("Literacy", "literacy_pct"));
        assert!(is_intensive_measure("Happiness Index", "happiness_index"));
        assert!(is_intensive_measure("Population Density", "pop_density"));
        // additive amounts/counts stay additive
        assert!(!is_intensive_measure(
            "Metro Population (millions)",
            "metro_population_m"
        ));
        assert!(!is_intensive_measure("Revenue", "revenue"));
        assert!(!is_intensive_measure("Packages", "packages"));
        assert!(!is_intensive_measure("Order Count", "order_count"));
        // a COUNT wins over an embedded intensive token — it is additive by definition
        assert!(!is_intensive_measure(
            "Review Score Count",
            "review_score_count"
        ));
        assert!(!is_intensive_measure("Index Count", "index_count"));
        assert!(!is_intensive_measure("Number of Ratings", "num_ratings"));
        // camelCase / PascalCase count fields are recognized even with an empty/unhelpful label
        assert!(!is_intensive_measure("", "reviewScoreCount"));
        assert!(!is_intensive_measure("", "indexCount"));
        assert!(!is_intensive_measure("", "numRatings"));
        // the count guard is token-aware: intensive fields that merely EMBED "count" as a
        // substring (discount, account, county) are still detected as intensive, in snake_case
        // and camelCase alike
        assert!(is_intensive_measure("Discount", "discount_pct"));
        assert!(is_intensive_measure("Account Score", "account_score"));
        assert!(is_intensive_measure("County Index", "county_index"));
        assert!(is_intensive_measure("", "discountPct"));
        assert!(is_intensive_measure("", "accountScore"));
    }

    #[test]
    fn derive_semantics_averages_intensive_measure() {
        let numeric = stat("Float", 300, Some(0.9));
        // temperature tagged as an additive amount by the coarse vocab -> downgraded to Mean
        let temp = derive_semantics(
            &numeric,
            Some(&dict_row(
                "",
                "measure",
                "measure.amount",
                "Average Annual Temperature (\u{b0}C)",
            )),
        );
        assert_eq!(temp.route, Route::Measure);
        assert_eq!(temp.agg, Some(Agg::Mean));
        // a genuine additive amount keeps Sum
        let pop = derive_semantics(
            &numeric,
            Some(&dict_row(
                "",
                "measure",
                "measure.amount",
                "Metro Population",
            )),
        );
        assert_eq!(pop.agg, Some(Agg::Sum));
        // an explicit measure.count stays additive even when its label embeds an intensive token
        // ("score"/"index") — a count is summed, never averaged.
        let counts = stat("Integer", 300, Some(0.9));
        let score_count = derive_semantics(
            &counts,
            Some(&dict_row(
                "",
                "measure",
                "measure.count",
                "Review Score Count",
            )),
        );
        assert_eq!(score_count.agg, Some(Agg::Sum));
    }

    #[test]
    fn route_from_content_type_legacy_mapping() {
        assert_eq!(route_from_content_type("category").0, Route::Dimension);
        assert_eq!(route_from_content_type("state_abbr").0, Route::Dimension);
        assert_eq!(route_from_content_type("latitude").0, Route::MapCoord);
        // temporal tokens, with/without an strftime or length suffix
        assert_eq!(route_from_content_type("date").0, Route::Temporal);
        assert_eq!(
            route_from_content_type("datetime:%Y-%m-%dT%H:%M:%S").0,
            Route::Temporal
        );
        assert_eq!(route_from_content_type("duration:3600").0, Route::Temporal);
        // identifiers / PII / free-text -> skip
        assert_eq!(route_from_content_type("unique_id").0, Route::Skip);
        assert_eq!(route_from_content_type("email").0, Route::Skip);
        assert_eq!(route_from_content_type("free_text").0, Route::Skip);
        // explicit / empty -> defer to stats
        assert_eq!(route_from_content_type("unknown").0, Route::Defer);
        assert_eq!(route_from_content_type("").0, Route::Defer);
    }

    #[test]
    fn derive_semantics_precedence_and_label() {
        // no dictionary row -> Defer (stats-only behavior unchanged)
        assert_eq!(
            derive_semantics(&stat("Integer", 5, None), None).route,
            Route::Defer
        );

        // concept beats a defaulted `measure` role: a numeric census_tract that describegpt left
        // role=measure is still routed to a Dimension bar by its geo.census_tract concept.
        let tract = stat("Integer", 33, Some(0.00003));
        let row = dict_row("", "measure", "geo.census_tract", "Census Tract");
        let sem = derive_semantics(&tract, Some(&row));
        assert_eq!(sem.route, Route::Dimension);
        assert_eq!(sem.label, "Census Tract"); // label carried for the panel title

        // role used when concept is absent/unknown
        let r = derive_semantics(
            &stat("String", 8, Some(0.01)),
            Some(&dict_row("", "dimension", "", "")),
        );
        assert_eq!(r.route, Route::Dimension);

        // content_type used when neither concept nor role resolve
        let c = derive_semantics(
            &stat("Float", 99, Some(0.5)),
            Some(&dict_row("latitude", "", "", "")),
        );
        assert_eq!(c.route, Route::MapCoord);

        // all-empty dictionary row -> Defer, but the label still rides along
        let d = derive_semantics(
            &stat("String", 9, Some(0.02)),
            Some(&dict_row("", "", "", "Notes")),
        );
        assert_eq!(d.route, Route::Defer);
        assert_eq!(d.label, "Notes");
    }

