    #[test]
    fn format_and_assemble_map_hover() {
        // dataset line: bold id + escaped extra
        let line = format_map_dataset_line(
            Some("Tokyo"),
            &[("Magnitude".to_string(), "5.2".to_string())],
        );
        assert_eq!(line, "<b>Tokyo</b><br>Magnitude: 5.2");
        // markup in values is escaped
        assert_eq!(
            format_map_dataset_line(Some("<b>x"), &[]),
            "<b>&lt;b&gt;x</b>"
        );

        // with an identifier, the geocoded place is a context line (no coord line — that's
        // appended at render by MAP_HOVER_TEMPLATE from the lat/lon data arrays)
        assert_eq!(
            assemble_map_hover("<b>Tokyo</b>", true, "Tokyo, Japan"),
            "<b>Tokyo</b><br>Tokyo, Japan"
        );
        // no identifier column: the geocoded place becomes the bold identifier
        assert_eq!(
            assemble_map_hover("", false, "Tokyo, Japan"),
            "<b>Tokyo, Japan</b>"
        );
        // empty when neither dataset nor geocode contributed — the template's coordinate
        // hover stands alone
        assert_eq!(assemble_map_hover("", false, ""), "");

        // map_hover_text_values: non-empty entries get the trailing <br> separator the
        // template relies on; empty entries stay empty (no leading blank line)
        assert_eq!(
            map_hover_text_values(&["<b>Tokyo</b>".to_string(), String::new()]),
            vec!["<b>Tokyo</b><br>".to_string(), String::new()]
        );
    }

    #[test]
    fn bdata_typed_array_roundtrip() {
        // below the size floor: left as a plain JSON array
        let mut small = serde_json::json!([1.0, 2.0]);
        bdata_encode_f32(&mut small);
        assert!(small.is_array(), "short arrays must stay plain JSON");

        // at the floor: becomes {"dtype":"float32","bdata":..} whose little-endian bytes
        // round-trip each value within f32 precision (~1e-4 deg at lat/lon magnitudes)
        let vals: Vec<f64> = (0..BDATA_MIN_LEN)
            .map(|i| 40.0 + i as f64 * 0.000_123_4)
            .collect();
        let mut v = serde_json::to_value(&vals).unwrap();
        bdata_encode_f32(&mut v);
        assert_eq!(v["dtype"], "float32");
        let bytes = base64_simd::STANDARD
            .decode_to_vec(v["bdata"].as_str().unwrap())
            .unwrap();
        assert_eq!(bytes.len(), vals.len() * 4);
        for (i, chunk) in bytes.chunks_exact(4).enumerate() {
            let f = f32::from_le_bytes([chunk[0], chunk[1], chunk[2], chunk[3]]);
            assert!(
                (f64::from(f) - vals[i]).abs() < 1e-4,
                "coordinate {i} drifted beyond f32 tolerance"
            );
        }

        // a non-numeric entry keeps the plain array (typed arrays can't carry gaps)
        let mut mixed = serde_json::to_value(vec![1.0_f64; BDATA_MIN_LEN]).unwrap();
        mixed.as_array_mut().unwrap()[10] = serde_json::Value::Null;
        bdata_encode_f32(&mut mixed);
        assert!(mixed.is_array(), "arrays with nulls must stay plain JSON");
    }

    #[test]
    fn map_panel_inline_html_encodes_and_escapes() {
        // a figure big enough to cross BDATA_MIN_LEN, with hover text containing a script
        // terminator — the emitted inline HTML must carry typed arrays and must never contain
        // a literal `</script>` inside the embedded JSON (askama-equivalent `\u003c` escaping).
        let n = BDATA_MIN_LEN;
        let lats: Vec<f64> = (0..n).map(|i| 40.0 + i as f64 * 0.001).collect();
        let lons: Vec<f64> = (0..n).map(|i| -80.0 + i as f64 * 0.001).collect();
        let texts: Vec<String> = (0..n).map(|_| "</script>x".to_string()).collect();
        let mut plot = Plot::new();
        plot.add_trace(
            ScatterMap::new(lats, lons)
                .mode(Mode::Markers)
                .text_array(texts)
                .hover_template(MAP_HOVER_TEMPLATE),
        );
        let html = map_panel_inline_html(&plot, "qsv-viz-panel-test");
        assert!(
            html.contains(r#""dtype":"float32""#) && html.contains(r#""bdata":""#),
            "lat/lon must embed as base64 typed arrays; html: {html}"
        );
        // exactly the two structural tags — none leaked from the embedded data
        assert_eq!(html.matches("</script>").count(), 1);
        assert_eq!(html.matches("<script").count(), 1);
        assert!(html.contains(r#"Plotly.newPlot("qsv-viz-panel-test""#));
    }

    #[cfg(feature = "geocode")]
    #[test]
    fn geocode_hover_place_gap_fills() {
        let label = crate::cmd::geocode::GeoLabel {
            city: "Kinshasa".to_string(),
            admin1: "Kinshasa City".to_string(),
            country: "Democratic Republic of Congo".to_string(),
            ..Default::default()
        };
        // nothing suppressed, empty dataset line -> the full place
        assert_eq!(
            geocode_hover_place(&label, false, false, false, false, ""),
            "Kinshasa, Kinshasa City, Democratic Republic of Congo"
        );
        // the city already appears in the dataset line (it's the identifier) -> dropped
        assert_eq!(
            geocode_hover_place(&label, false, false, false, false, "<b>Kinshasa</b>"),
            "Kinshasa City, Democratic Republic of Congo"
        );
        // concept suppression (a chosen geo.country column) drops the country
        assert_eq!(
            geocode_hover_place(&label, false, false, true, false, ""),
            "Kinshasa, Kinshasa City"
        );

        // county (admin2) is always-on, between admin1 and country
        let us = crate::cmd::geocode::GeoLabel {
            city: "Pittsburgh".to_string(),
            admin1: "Pennsylvania".to_string(),
            country: "United States".to_string(),
            admin2: "Allegheny County".to_string(),
            us_state_fips: "42".to_string(),
            us_county_fips: "42003".to_string(),
            ..Default::default()
        };
        assert_eq!(
            geocode_hover_place(&us, false, false, false, false, ""),
            "Pittsburgh, Allegheny County, Pennsylvania, United States"
        );
        // FIPS appended only when verbose (--smarter): prefer the 5-digit county FIPS
        assert_eq!(
            geocode_hover_place(&us, false, false, false, true, ""),
            "Pittsburgh, Allegheny County, Pennsylvania, United States (FIPS 42003)"
        );
        // verbose but only a state FIPS -> the 2-digit state FIPS
        let state_only = crate::cmd::geocode::GeoLabel {
            city: "Somewhere".to_string(),
            admin1: "Pennsylvania".to_string(),
            country: "United States".to_string(),
            us_state_fips: "42".to_string(),
            ..Default::default()
        };
        assert_eq!(
            geocode_hover_place(&state_only, false, false, false, true, ""),
            "Somewhere, Pennsylvania, United States (FIPS 42)"
        );
        // non-US place under verbose -> no FIPS tail
        assert_eq!(
            geocode_hover_place(&label, false, false, false, true, ""),
            "Kinshasa, Kinshasa City, Democratic Republic of Congo"
        );
    }

    #[test]
    fn guardrail_downgrades_only_code_like_measures() {
        // a low-cardinality integer over many rows, role-defaulted to measure with no concept ->
        // downgraded to a Dimension bar (the fact-#2 defense).
        let code = stat("Integer", 6, Some(0.00001));
        assert_eq!(
            derive_semantics(&code, Some(&dict_row("", "measure", "", ""))).route,
            Route::Dimension
        );
        // a tiny fixed integer scale (ordinal rating) is barred even with an EXPLICIT measure.*
        // concept: a 1-5 satisfaction score lands on measure.count/amount but charts far better as
        // a frequency bar of its levels than as a box plot.
        assert_eq!(
            derive_semantics(&code, Some(&dict_row("", "measure", "measure.count", ""))).route,
            Route::Dimension
        );
        let rating = stat("Integer", 5, Some(0.01));
        assert_eq!(
            derive_semantics(
                &rating,
                Some(&dict_row("", "measure", "measure.amount", ""))
            )
            .route,
            Route::Dimension
        );
        // boundary: a 1-5 rating over exactly 100 rows -> uniqueness ratio == 0.05. The `<=`
        // threshold bars it (a `<` would leave it a box).
        assert_eq!(
            derive_semantics(
                &stat("Integer", 5, Some(0.05)),
                Some(&dict_row("", "measure", "measure.amount", ""))
            )
            .route,
            Route::Dimension
        );
        // an EXPLICIT measure.* concept whose cardinality is above RATING_MAX_CARDINALITY but still
        // categorical (13..=30) is trusted as a genuine measure -> stays Measure. The tighter
        // rating threshold only bars a handful of discrete levels, unlike the role-defaulted path.
        assert_eq!(
            derive_semantics(
                &stat("Integer", 20, Some(0.001)),
                Some(&dict_row("", "measure", "measure.count", ""))
            )
            .route,
            Route::Measure
        );
        // a float is ~never a code -> stays Measure
        assert_eq!(
            derive_semantics(
                &stat("Float", 6, Some(0.00001)),
                Some(&dict_row("", "measure", "", ""))
            )
            .route,
            Route::Measure
        );
        // a near-unique integer (genuine continuous) -> stays Measure
        assert_eq!(
            derive_semantics(
                &stat("Integer", 100_000, Some(0.99)),
                Some(&dict_row("", "measure", "", ""))
            )
            .route,
            Route::Measure
        );
        // residual gap (documented): cardinality above CATEGORICAL_MAX_CARDINALITY is left to the
        // concept layer, NOT the guardrail -> stays Measure.
        assert_eq!(
            derive_semantics(
                &stat("Integer", 50, Some(0.00001)),
                Some(&dict_row("", "measure", "", ""))
            )
            .route,
            Route::Measure
        );
    }

    #[test]
    fn classify_with_semantics_routes() {
        // Defer falls back to classify (low-card string -> frequency bar)
        let sem_defer = ColSemantics::default();
        assert!(matches!(
            classify_with_semantics(0, &stat("String", 5, Some(0.001)), &sem_defer, false),
            Some(PanelKind::FreqBar { idx: 0 })
        ));
        // Dimension -> frequency bar even for a many-distinct integer code
        let sem_dim = ColSemantics {
            route: Route::Dimension,
            ..Default::default()
        };
        assert!(matches!(
            classify_with_semantics(2, &stat("Integer", 500, Some(0.4)), &sem_dim, false),
            Some(PanelKind::FreqBar { idx: 2 })
        ));
        // Measure -> box plot from quartiles (via classify_measure)
        let mut m = stat("Integer", 500, Some(0.4));
        m.q1 = Some(10.0);
        m.q2_median = Some(20.0);
        m.q3 = Some(30.0);
        let sem_meas = ColSemantics {
            route: Route::Measure,
            ..Default::default()
        };
        assert!(matches!(
            classify_with_semantics(3, &m, &sem_meas, false),
            Some(PanelKind::BoxStats { .. })
        ));
        // Temporal / Skip draw no per-column panel
        for route in [Route::Temporal, Route::Skip] {
            let sem = ColSemantics {
                route,
                ..Default::default()
            };
            assert!(
                classify_with_semantics(0, &stat("DateTime", 9, Some(0.6)), &sem, false).is_none()
            );
        }
        // MapCoord falls back to classify: a coordinate the map did NOT consume (the caller already
        // skips consumed ones via is_map_col) must still be charted, not vanish. A near-unique
        // float with quartiles -> box.
        let mut coord = stat("Float", 5000, Some(0.99));
        coord.q1 = Some(1.0);
        coord.q2_median = Some(2.0);
        coord.q3 = Some(3.0);
        let sem_coord = ColSemantics {
            route: Route::MapCoord,
            ..Default::default()
        };
        assert!(matches!(
            classify_with_semantics(7, &coord, &sem_coord, false),
            Some(PanelKind::BoxStats { .. })
        ));
        // ProjectedCoord (state-plane easting/northing) is gated on whether a point map rendered:
        // with a map its spatial spread is already on screen in 2-D, so no redundant 1-D box;
        // without one it falls back to classify_measure rather than vanish.
        let sem_planar = ColSemantics {
            route: Route::ProjectedCoord,
            ..Default::default()
        };
        let mut planar = stat("Integer", 8130, Some(0.81));
        planar.q1 = Some(993_041.5);
        planar.q2_median = Some(1_005_000.0);
        planar.q3 = Some(1_018_194.0);
        assert!(classify_with_semantics(8, &planar, &sem_planar, true).is_none());
        assert!(matches!(
            classify_with_semantics(8, &planar, &sem_planar, false),
            Some(PanelKind::BoxStats { .. })
        ));
        // ... and it must go through `classify_measure`, NOT `classify`, which would drop a
        // near-unique INTEGER column as ID-like. State-plane coords are integer feet, so on a
        // finely-spread dataset uniqueness_ratio clears 0.95 — the regression this route exists to
        // prevent. (Regression test for roborev 3536.)
        let mut planar_uniq = stat("Integer", 2000, Some(1.0));
        planar_uniq.q1 = Some(947_825.0);
        planar_uniq.q2_median = Some(982_500.0);
        planar_uniq.q3 = Some(1_017_175.0);
        assert!(
            classify(9, &planar_uniq).is_none(),
            "classify drops it as ID-like"
        );
        assert!(
            matches!(
                classify_with_semantics(9, &planar_uniq, &sem_planar, false),
                Some(PanelKind::BoxStats { .. })
            ),
            "ProjectedCoord must bypass the near-unique-integer ID guard"
        );
        // still suppressed when a map rendered, regardless of uniqueness
        assert!(classify_with_semantics(9, &planar_uniq, &sem_planar, true).is_none());
    }

    #[test]
    fn classify_measure_box_histogram_none() {
        // quartiles present -> box plot
        let mut s = stat("Float", 500, Some(0.9));
        s.q1 = Some(1.0);
        s.q2_median = Some(2.0);
        s.q3 = Some(3.0);
        assert!(matches!(
            classify_measure(1, &s),
            Some(PanelKind::BoxStats { .. })
        ));
        // flagged bimodal AND platykurtic (negative excess kurtosis) -> histogram
        s.bimodality_coefficient = Some(BIMODALITY_COEFFICIENT_THRESHOLD + 0.01);
        s.kurtosis = Some(-1.0);
        assert!(matches!(
            classify_measure(1, &s),
            Some(PanelKind::Histogram { .. })
        ));
        // high BC but LEPTOKURTIC (skewed unimodal, e.g. a long-tailed/outlier column) stays a box
        s.kurtosis = Some(5.0);
        assert!(matches!(
            classify_measure(1, &s),
            Some(PanelKind::BoxStats { .. })
        ));
        // no quartiles -> nothing to chart
        assert!(classify_measure(1, &stat("Integer", 500, Some(0.9))).is_none());
    }

    #[test]
    fn parse_dictionary_semantics_jsonschema_shape() {
        // a describegpt --format jsonschema doc: label rides as `title`, semantic tokens in
        // x-qsv, dataset grain at the top-level x-qsv.
        let schema = r#"{
          "$schema": "https://json-schema.org/draft/2020-12/schema",
          "type": "object",
          "properties": {
            "census_tract": { "type": ["integer","null"], "title": "Census Tract",
              "x-qsv": { "qsv_type": "Integer", "content_type": "category",
                         "role": "dimension", "concept": "geo.census_tract" } },
            "amount": { "type": "number", "title": "Amount",
              "x-qsv": { "qsv_type": "Float", "role": "measure", "concept": "measure.amount" } },
            "notes": { "type": "string", "x-qsv": { "qsv_type": "String" } }
          },
          "x-qsv": { "grain": "one row = one 311 service request" }
        }"#;
        let data = parse_dictionary_semantics(schema).expect("schema should parse");
        let tract = data.rows.get("census_tract").expect("census_tract row");
        assert_eq!(tract.role, "dimension");
        assert_eq!(tract.concept, "geo.census_tract");
        assert_eq!(tract.content_type, "category");
        assert_eq!(tract.label, "Census Tract");
        let amount = data.rows.get("amount").expect("amount row");
        assert_eq!(amount.concept, "measure.amount");
        // a property with a bare x-qsv (no role/concept) still parses with empty signals
        let notes = data.rows.get("notes").expect("notes row");
        assert!(notes.role.is_empty() && notes.concept.is_empty());
        assert_eq!(
            data.grain.as_deref(),
            Some("one row = one 311 service request")
        );

        // end-to-end: the parsed census_tract row routes to a Dimension bar.
        assert_eq!(
            derive_semantics(&stat("Integer", 33, Some(0.00003)), Some(tract)).route,
            Route::Dimension
        );
    }

    #[test]
    fn render_dict_page_html_groups_stats_and_guards_sci_notation() {
        // Range min/max grouping is role-gated: only genuine `measure` columns get thousands
        // separators on their range. Identifiers, geo codes (ZIP) and years are dimensions, so
        // their ranges render verbatim (a ZIP 15003 must never read "15,003", a year 2099 never
        // "2,099"). Cardinality/null_count are always counts and stay grouped regardless of role.
        // Extreme-magnitude float min/max serialize in scientific notation via serde_json
        // (`1e-7`, `1e+100`); grouping must leave those intact rather than mangle them into
        // `1,e-7` / `1e+,100`.
        let schema = r#"{
          "$schema": "https://json-schema.org/draft/2020-12/schema",
          "type": "object",
          "properties": {
            "account_id": { "type": "integer", "title": "Account ID",
              "minimum": 1000001, "maximum": 3000003,
              "x-qsv": { "role": "identifier", "cardinality": 1234567, "null_count": 4210 } },
            "owner_zip": { "type": "integer", "title": "Owner ZIP",
              "minimum": 15003, "maximum": 47909,
              "x-qsv": { "role": "dimension", "concept": "geo.zip_code" } },
            "exp_year": { "type": "integer", "title": "Expiration Year",
              "minimum": 2099, "maximum": 2099,
              "x-qsv": { "role": "dimension", "concept": "unknown" } },
            "revenue": { "type": "integer", "title": "Revenue",
              "minimum": 4000004, "maximum": 9000009,
              "x-qsv": { "role": "measure", "concept": "measure.value" } },
            "tiny": { "type": "number", "title": "Tiny",
              "minimum": 1e-7, "maximum": 1e100,
              "x-qsv": { "role": "measure", "concept": "measure.value", "cardinality": 3, "null_count": 0 } }
          },
          "x-qsv": { "grain": "one row = one account" }
        }"#;
        let dict_json: serde_json::Value = serde_json::from_str(schema).unwrap();
        let order = vec![
            "account_id".to_string(),
            "owner_zip".to_string(),
            "exp_year".to_string(),
            "revenue".to_string(),
            "tiny".to_string(),
        ];
        let html = render_dict_page_html(
            &dict_json,
            schema,
            &DictData::default(),
            "Accounts",
            &order,
            &std::collections::HashSet::new(),
        );

        // a JSON Schema dictionary (top-level `properties`) offers a script-free "Export
        // JSONSchema" download: a plain <a download> carrying the verbatim schema as a base64
        // data: URI, with a title-derived filename.
        assert!(
            html.contains(r#"class="qsv-dict-export""#),
            "jsonschema dict offers an export link"
        );
        assert!(
            html.contains(r#"download="accounts.schema.json""#),
            "export filename derives from the dataset title"
        );
        assert!(
            html.contains("href=\"data:application/json;base64,"),
            "export rides as a base64 data: URI"
        );

        // measure range IS comma-grouped; cardinality and null_count are always grouped
        assert!(
            html.contains("4,000,004 \u{2013} 9,000,009"),
            "measure range grouped"
        );
        assert!(html.contains("<dd>1,234,567</dd>"), "cardinality grouped");
        assert!(html.contains("<dd>4,210</dd>"), "null_count grouped");

        // non-measure ranges render verbatim: identifier, ZIP code and year are never grouped
        assert!(
            html.contains("1000001 \u{2013} 3000003"),
            "identifier range not grouped"
        );
        assert!(!html.contains("1,000,001"), "identifier range not mangled");
        assert!(
            html.contains("15003 \u{2013} 47909"),
            "ZIP range not grouped"
        );
        assert!(!html.contains("15,003"), "ZIP not comma-mangled");
        assert!(
            html.contains("2099 \u{2013} 2099"),
            "year range not grouped"
        );
        assert!(!html.contains("2,099"), "year not comma-mangled");

        // scientific-notation floats are preserved verbatim (serde_json emits `1e+100`),
        // and never appear in the comma-mangled forms group_thousands would otherwise yield.
        assert!(
            html.contains("1e-7 \u{2013} 1e+100"),
            "exponent range preserved"
        );
        assert!(
            !html.contains("1,e-7"),
            "no comma-mangled negative exponent"
        );
        assert!(
            !html.contains("1e+,100"),
            "no comma-mangled positive exponent"
        );
    }

    #[test]
    fn render_dict_page_html_legacy_fields_dict_has_no_jsonschema_export() {
        // A legacy `fields` dictionary is NOT JSON Schema, so the "Export JSONSchema" control
        // must not appear (the label would be a lie); only top-level `properties` dicts get it.
        let legacy = r#"{
          "fields": [
            { "name": "account_id", "role": "identifier", "content_type": "integer" },
            { "name": "revenue", "role": "measure", "content_type": "float" }
          ]
        }"#;
        let dict_json: serde_json::Value = serde_json::from_str(legacy).unwrap();
        let order = vec!["account_id".to_string(), "revenue".to_string()];
        let html = render_dict_page_html(
            &dict_json,
            legacy,
            &DictData::default(),
            "Accounts",
            &order,
            &std::collections::HashSet::new(),
        );
        // the stylesheet always carries `.qsv-dict-export` rules; assert on the ANCHOR markup
        // (and the data: URI) so we're checking the control, not the CSS.
        assert!(
            !html.contains(r#"class="qsv-dict-export""#),
            "legacy fields dict renders no export anchor"
        );
        assert!(
            !html.contains("data:application/json;base64,"),
            "legacy fields dict embeds no schema download"
        );
    }

    #[test]
    fn parse_dictionary_semantics_captures_descriptions() {
        // jsonschema shape: per-field `description`, dataset description at the top level
        // (describegpt --description folds it there under --format jsonschema), provenance
        // in x-qsv.generated_by.
        let schema = r#"{
          "$schema": "https://json-schema.org/draft/2020-12/schema",
          "type": "object",
          "description": "311 service requests for 2026.",
          "properties": {
            "census_tract": { "type": ["integer","null"], "title": "Census Tract",
              "description": "The 2020 census tract containing the incident.",
              "x-qsv": { "role": "dimension", "concept": "geo.census_tract" } },
            "amount": { "type": "number", "title": "Amount" }
          },
          "x-qsv": { "grain": "one row = one request",
            "generated_by": "Generated by qsv describegpt\nModel: test-model" }
        }"#;
        let data = parse_dictionary_semantics(schema).expect("schema should parse");
        assert_eq!(
            data.rows["census_tract"].description,
            "The 2020 census tract containing the incident."
        );
        assert_eq!(data.rows["amount"].description, "");
        assert_eq!(
            data.dataset_description.as_deref(),
            Some("311 service requests for 2026.")
        );
        assert!(
            data.generated_by
                .as_deref()
                .is_some_and(|g| g.contains("Model: test-model"))
        );

        // legacy shape: per-field `description` only; no dataset description / provenance.
        let legacy = r#"{"fields":[
            {"name":"a","content_type":"category","description":"Column A holds categories."}
        ]}"#;
        let data = parse_dictionary_semantics(legacy).expect("legacy should parse");
        assert_eq!(data.rows["a"].description, "Column A holds categories.");
        assert!(data.dataset_description.is_none());
        assert!(data.generated_by.is_none());
    }

    #[test]
    fn render_dict_markdown_basic_formatting() {
        // bold, italic, inline code
        assert_eq!(
            render_dict_markdown("A **bold** and *italic* and `code` word."),
            "<p>A <strong>bold</strong> and <em>italic</em> and <code>code</code> word.</p>\n"
        );
        // __bold__ / _italic_ variants
        assert_eq!(
            render_dict_markdown("__strong__ then _emph_"),
            "<p><strong>strong</strong> then <em>emph</em></p>\n"
        );
    }

    #[test]
    fn parse_dictionary_semantics_strips_attribution_from_dataset_description() {
        // describegpt appends its "Generated by … WARNING:" provenance to the dataset
        // description; it must be stripped (it's shown separately as the page footer).
        let schema = r#"{
          "type": "object",
          "description": "Municipal service requests.\n\n### Notable Characteristics\n\n* High volume.\n\nGenerated by qsv v21.1.0 describegpt\nModel: test-model\n\nWARNING: Description generated by an LLM and may contain inaccuracies. Verify before using!",
          "properties": { "a": { "type": "string", "title": "A" } },
          "x-qsv": { "generated_by": "Generated by qsv v21.1.0 describegpt\nModel: test-model" }
        }"#;
        let data = parse_dictionary_semantics(schema).expect("schema should parse");
        let desc = data
            .dataset_description
            .expect("dataset description present");
        assert!(desc.contains("Municipal service requests."));
        assert!(desc.contains("### Notable Characteristics"));
        assert!(desc.contains("High volume."));
        assert!(!desc.contains("Generated by"), "attribution not stripped");
        assert!(!desc.contains("WARNING"), "warning not stripped");
        // the footer still carries the provenance separately
        assert!(data.generated_by.is_some_and(|g| g.contains("test-model")));

        // a mid-sentence "Generated by" that is NOT a line-anchored describegpt footer must
        // be preserved (no truncation).
        let mid = r#"{
          "type": "object",
          "description": "This dataset was Generated by the city's 311 system in 2015.",
          "properties": { "a": { "type": "string" } }
        }"#;
        let data = parse_dictionary_semantics(mid).expect("schema should parse");
        assert_eq!(
            data.dataset_description.as_deref(),
            Some("This dataset was Generated by the city's 311 system in 2015.")
        );
    }

    #[test]
    fn strip_dataset_attribution_footer_forms() {
        // plain line-anchored footer (the jsonschema `description` form)
        assert_eq!(
            strip_dataset_attribution(
                "Some description.\n\nGenerated by qsv v20.1.0 describegpt\nWARNING: ..."
            ),
            "Some description."
        );
        // markdown footer: `*Attribution: Generated by … describegpt …*`
        assert_eq!(
            strip_dataset_attribution(
                "Some description.\n\n*Attribution: Generated by qsv v20.1.0 \
                 describegpt*\nWARNING: ...*"
            ),
            "Some description."
        );
        // TOON footer: `Attribution: Generated by …`
        assert_eq!(
            strip_dataset_attribution(
                "Some description.\n\nAttribution: Generated by qsv v20.1.0 describegpt"
            ),
            "Some description."
        );
        // dangling `---` rule and `**Attribution**` heading above the footer are trimmed
        assert_eq!(
            strip_dataset_attribution(
                "Some description.\n\n---\n\n**Attribution**\n\nGenerated by qsv v20.1.0 \
                 describegpt\nWARNING: ..."
            ),
            "Some description."
        );
        // a "Generated by" line WITHOUT the describegpt signature is preserved (not a footer)
        assert_eq!(
            strip_dataset_attribution("Generated by the city's 311 system.\n\nMore prose."),
            "Generated by the city's 311 system.\n\nMore prose."
        );
        // no footer at all: only trailing whitespace trimmed
        assert_eq!(strip_dataset_attribution("Just text.\n"), "Just text.");
    }

    #[test]
    fn render_dict_markdown_atx_headings() {
        // describegpt descriptions commonly use `### Notable Characteristics` sub-headings.
        let html = render_dict_markdown("Intro.\n\n### Notable Characteristics\n\n* one\n* two");
        assert_eq!(
            html,
            "<p>Intro.</p>\n<h4 class=\"qsv-dict-mdh\">Notable \
             Characteristics</h4>\n<ul><li>one</li><li>two</li></ul>\n"
        );
        // all levels normalize to <h4>; inline markup inside the heading still renders.
        assert!(
            render_dict_markdown("# Big **title**")
                .contains("<h4 class=\"qsv-dict-mdh\">Big <strong>title</strong></h4>")
        );
        // not a heading without the trailing space (e.g. a hashtag)
        assert_eq!(render_dict_markdown("#nothashtag"), "<p>#nothashtag</p>\n");
        // a trailing '#' that isn't a space-preceded ATX closing sequence is content
        assert_eq!(
            render_dict_markdown("### C#"),
            "<h4 class=\"qsv-dict-mdh\">C#</h4>\n"
        );
        // a proper closing sequence (preceded by a space) IS stripped
        assert_eq!(
            render_dict_markdown("### Heading ###"),
            "<h4 class=\"qsv-dict-mdh\">Heading</h4>\n"
        );
    }

    #[test]
    fn render_dict_markdown_bullet_list() {
        let html = render_dict_markdown("Intro line.\n\n- first\n- second **bold**\n- third");
        assert_eq!(
            html,
            "<p>Intro line.</p>\n<ul><li>first</li><li>second \
             <strong>bold</strong></li><li>third</li></ul>\n"
        );
    }

    #[test]
    fn render_dict_markdown_paragraphs_and_softbreaks() {
        // blank line splits paragraphs; single newline collapses to a space.
        let html = render_dict_markdown("Line one\nstill one.\n\nSecond para.");
        assert_eq!(html, "<p>Line one still one.</p>\n<p>Second para.</p>\n");
    }

    #[test]
    fn render_dict_markdown_safe_links() {
        assert_eq!(
            render_dict_markdown("See [docs](https://example.com/a?b=1)."),
            "<p>See <a href=\"https://example.com/a?b=1\" target=\"_blank\" rel=\"noopener \
             noreferrer\">docs</a>.</p>\n"
        );
        // relative + anchor links are allowed
        assert!(render_dict_markdown("[x](#anchor)").contains("href=\"#anchor\""));
        assert!(render_dict_markdown("[x](/page)").contains("href=\"/page\""));
    }

    #[test]
    fn render_dict_markdown_underscores_are_not_intraword_emphasis() {
        // A snake_case identifier must NOT become emphasized.
        assert_eq!(
            render_dict_markdown("The first_name column."),
            "<p>The first_name column.</p>\n"
        );
    }

    #[test]
    fn render_dict_markdown_escapes_raw_html_no_xss() {
        // Raw HTML is escaped, never passed through — no live tag, no </script> breakout.
        let html = render_dict_markdown("<img src=x onerror=alert(1)> and </script> here");
        assert!(!html.contains("<img"));
        assert!(!html.contains("</script>"));
        assert!(html.contains("&lt;img"));
        assert!(html.contains("&lt;/script&gt;"));
    }

    #[test]
    fn render_dict_markdown_rejects_dangerous_url_schemes() {
        // javascript:/data:/vbscript: links drop the anchor and render as plain text.
        let js = render_dict_markdown("[click](javascript:alert(1))");
        assert!(!js.contains("href"));
        assert!(!js.contains("javascript:"));
        assert_eq!(js, "<p>click</p>\n");

        let data = render_dict_markdown("[x](data:text/html,<script>alert(1)</script>)");
        assert!(!data.contains("href"));
        assert!(!data.contains("<script>"));

        let vb = render_dict_markdown("[x](vbscript:msgbox(1))");
        assert!(!vb.contains("href"));
    }

    #[test]
    fn render_dict_markdown_escapes_special_chars_in_text() {
        assert_eq!(
            render_dict_markdown(r#"a & b < c > d "e""#),
            "<p>a &amp; b &lt; c &gt; d &quot;e&quot;</p>\n"
        );
    }

    #[test]
    fn parse_dictionary_semantics_legacy_and_garbage() {
        // legacy --format json dictionary (content_type only, no role/concept/grain)
        let json = r#"{
          "Dictionary": { "response": { "fields": [
            { "name": "status", "type": "String", "content_type": "category", "label": "Status" },
            { "name": "id", "type": "String" }
          ] } }
        }"#;
        let data = parse_dictionary_semantics(json).expect("legacy json should parse");
        let status = data.rows.get("status").expect("status row");
        assert_eq!(status.content_type, "category");
        assert_eq!(status.label, "Status");
        assert!(status.role.is_empty() && status.concept.is_empty());
        // a field with no content_type is still present (carries empty signals)
        assert!(data.rows.contains_key("id"));
        assert!(data.grain.is_none());

        // a bare {"fields":[...]} envelope also works
        let bare = r#"{"fields":[{"name":"x","content_type":"category"}]}"#;
        assert!(parse_dictionary_semantics(bare).is_some());

        // garbage / wrong-shaped JSON yields None (caller degrades gracefully)
        assert!(parse_dictionary_semantics("not json").is_none());
        assert!(parse_dictionary_semantics(r#"{"foo":1}"#).is_none());
    }

    #[test]
    fn timestamp_rank_prefers_event_and_created() {
        // event/created lead; closed/updated/due secondary; bare date or no concept last
        assert!(timestamp_rank("time.event_timestamp") < timestamp_rank("time.created_at"));
        assert!(timestamp_rank("time.created_at") < timestamp_rank("time.closed_at"));
        assert!(timestamp_rank("time.closed_at") < timestamp_rank("time.date"));
        assert_eq!(
            timestamp_rank("time.updated_at"),
            timestamp_rank("time.due_at")
        );
        assert_eq!(timestamp_rank(""), timestamp_rank("time.date")); // no concept == bare date
    }

    #[test]
    fn ts_bucket_span_thresholds_and_keys() {
        use chrono::NaiveDate;
        assert_eq!(ts_bucket_for_span(0), TsBucket::Day);
        assert_eq!(ts_bucket_for_span(370), TsBucket::Day);
        assert_eq!(ts_bucket_for_span(371), TsBucket::Week);
        assert_eq!(ts_bucket_for_span(1825), TsBucket::Week);
        assert_eq!(ts_bucket_for_span(1826), TsBucket::Month);

        // a Wednesday truncates to its ISO-week Monday, and to the 1st of its month
        let wed = NaiveDate::from_ymd_opt(2024, 5, 1).unwrap(); // 2024-05-01 is a Wednesday
        assert_eq!(ts_bucket_key(wed, TsBucket::Day), wed);
        assert_eq!(
            ts_bucket_key(wed, TsBucket::Week),
            NaiveDate::from_ymd_opt(2024, 4, 29).unwrap() // Monday
        );
        assert_eq!(
            ts_bucket_key(wed, TsBucket::Month),
            NaiveDate::from_ymd_opt(2024, 5, 1).unwrap()
        );
        // labels: ISO date for day/week, YYYY-MM for month
        assert_eq!(ts_bucket_label(wed, TsBucket::Day), "2024-05-01");
        assert_eq!(ts_bucket_label(wed, TsBucket::Month), "2024-05");
    }

    #[test]
    fn count_unit_from_grain_extracts_or_falls_back() {
        assert_eq!(
            count_unit_from_grain(Some("one row = one 311 service request")),
            "311 service request"
        );
        assert_eq!(
            count_unit_from_grain(Some("each row is one order.")),
            "order"
        );
        // no " one " pattern -> fallback
        assert_eq!(
            count_unit_from_grain(Some("each row represents a person")),
            "records"
        );
        // absent grain -> fallback
        assert_eq!(count_unit_from_grain(None), "records");
        // implausibly long tail -> fallback (guards against a runaway grain sentence)
        let long = format!("one row = one {}", "x".repeat(60));
        assert_eq!(count_unit_from_grain(Some(&long)), "records");
    }

    #[test]
    fn code_twin_base_strips_key_suffixes() {
        assert_eq!(code_twin_base("subject_code"), Some("subject"));
        assert_eq!(code_twin_base("street_id"), Some("street"));
        assert_eq!(code_twin_base("region_key"), Some("region"));
        // no key suffix, or suffix-only -> None
        assert_eq!(code_twin_base("subject"), None);
        assert_eq!(code_twin_base("_code"), None);
        // bare "id"/"code" (no underscore) is NOT a twin suffix
        assert_eq!(code_twin_base("zipcode"), None);
    }

    #[test]
    fn dimension_code_twins_suppresses_only_paired_keys() {
        // build a 4-column frame: subject (dim) + subject_code (dim) + street (dim) + lonely_id
        // (dim)
        let stats = [
            {
                let mut s = stat("String", 20, Some(0.01));
                s.field = "subject".to_string();
                s
            },
            {
                let mut s = stat("Integer", 20, Some(0.01));
                s.field = "subject_code".to_string();
                s
            },
            {
                let mut s = stat("String", 20, Some(0.01));
                s.field = "street".to_string();
                s
            },
            {
                let mut s = stat("Integer", 20, Some(0.01));
                s.field = "lonely_id".to_string();
                s
            },
        ];
        let dim = ColSemantics {
            route: Route::Dimension,
            ..Default::default()
        };
        let sems = [dim.clone(), dim.clone(), dim.clone(), dim.clone()];
        let suppress = dimension_code_twins(&stats, &sems);
        // subject_code is suppressed (its label sibling `subject` is charted) ...
        assert!(suppress.contains(&1));
        // ... but subject, street, and lonely_id (no `lonely` sibling) are kept
        assert!(!suppress.contains(&0));
        assert!(!suppress.contains(&2));
        assert!(!suppress.contains(&3));

        // a *_code with no charted label sibling is NOT suppressed
        let orphan_stats = [{
            let mut s = stat("Integer", 20, Some(0.01));
            s.field = "ward_code".to_string();
            s
        }];
        let orphan_sems = [dim];
        assert!(dimension_code_twins(&orphan_stats, &orphan_sems).is_empty());
    }

