    #[test]
    fn lon_center_and_span_empty_is_degenerate() {
        // empty input must not panic on the sorted[0]/sorted[n - 1] indexing -> degenerate (0, 0)
        assert_eq!(lon_center_and_span(&[], 0.0), (0.0, 0.0));
    }

    #[test]
    fn lon_center_and_span_crossing_trims_outlier() {
        // a tight cluster straddling +/-180 plus one far in-range longitude outlier (80). The
        // crossing branch must trim like the non-crossing one: untrimmed, the unwrapped span runs
        // from the outlier (~80) to the cluster (~182) and reads as global; trimming the outlier
        // away keeps the span local.
        let mut lons = vec![80.0_f64]; // single far outlier
        for k in 0..100 {
            lons.push(178.0 + (k % 2) as f64); // 178 / 179
            lons.push(-179.0 + (k % 2) as f64); // -179 / -178
        }
        let (_, untrimmed) = lon_center_and_span(&lons, 0.0);
        let (_, trimmed) = lon_center_and_span(&lons, MAP_FRAME_TRIM_FRAC);
        assert!(
            untrimmed >= 90.0,
            "untrimmed crossing span should include the outlier, got {untrimmed}"
        );
        assert!(
            trimmed < 10.0,
            "trimmed crossing span should exclude the outlier, got {trimmed}"
        );
    }

    #[test]
    fn sorted_quantile_nearest_rank() {
        let s: Vec<f64> = (0..=100).map(f64::from).collect(); // 0..=100
        assert_eq!(sorted_quantile(&s, 0.0), 0.0);
        assert_eq!(sorted_quantile(&s, 1.0), 100.0);
        assert_eq!(sorted_quantile(&s, 0.5), 50.0);
        assert_eq!(sorted_quantile(&s, 0.01), 1.0);
        assert_eq!(sorted_quantile(&s, 0.99), 99.0);
        assert_eq!(sorted_quantile(&[], 0.5), 0.0); // empty -> 0.0
    }

    #[test]
    fn downsample_pair_caps_and_preserves_shape() {
        let xs: Vec<f64> = (0..1000).map(f64::from).collect();
        let ys: Vec<f64> = xs.iter().map(|v| v * 2.0).collect();
        let (dx, dy) = downsample_pair(&xs, &ys, 100);
        assert_eq!(dx.len(), 100);
        assert_eq!(dy.len(), 100);
        // row alignment is preserved (ys == 2*xs throughout)
        assert!(dx.iter().zip(&dy).all(|(x, y)| (y - x * 2.0).abs() < 1e-9));
        // endpoint-inclusive: both the first AND the last observation are retained, so a
        // chronologically sorted time-series keeps its latest point
        assert_eq!(dx[0], 0.0);
        assert_eq!(*dx.last().unwrap(), 999.0);
        assert_eq!(*dy.last().unwrap(), 1998.0);
        // single-element cap doesn't divide by zero and returns the first point
        assert_eq!(downsample_pair(&xs, &ys, 1), (vec![0.0], vec![0.0]));
        // already within cap -> returned unchanged
        let (sx, sy) = downsample_pair(&xs[..50], &ys[..50], 100);
        assert_eq!(sx.len(), 50);
        assert_eq!(sy.len(), 50);
        // cap == 0 -> unchanged (no divide-by-zero)
        assert_eq!(downsample_pair(&xs, &ys, 0).0.len(), 1000);
    }

    #[test]
    fn lttb_indices_keeps_endpoints_and_spike() {
        // a flat baseline with a single tall spike that sits BETWEEN uniform-stride samples
        let n = 1000;
        let cap = 50;
        let spike = 333usize; // 333 * (n-1) / (cap-1) is not an integer -> stride would miss it
        let xs: Vec<f64> = (0..n).map(|i| i as f64).collect();
        let ys: Vec<f64> = (0..n)
            .map(|i| if i == spike { 1000.0 } else { 0.0 })
            .collect();

        // baseline: uniform stride steps right over the spike
        let stride: Vec<usize> = (0..cap).map(|i| i * (n - 1) / (cap - 1)).collect();
        assert!(
            !stride.contains(&spike),
            "test precondition: stride must miss the spike"
        );
        let (_, stride_y) = downsample_pair(&xs, &ys, cap);
        assert!(
            stride_y.iter().all(|&y| y < 1.0),
            "uniform stride drops the spike"
        );

        // LTTB selects by triangle area, so the spike survives
        let keep = lttb_indices(&xs, &ys, cap);
        assert_eq!(keep.len(), cap);
        assert_eq!(keep[0], 0, "first point always kept");
        assert_eq!(*keep.last().unwrap(), n - 1, "last point always kept");
        assert!(
            keep.contains(&spike),
            "LTTB preserves the peak a uniform stride misses"
        );
        // indices are strictly increasing (monotonic selection)
        assert!(keep.windows(2).all(|w| w[0] < w[1]));

        // edge caps: no panic, sensible output
        assert_eq!(lttb_indices(&xs, &ys, 0), (0..n).collect::<Vec<_>>());
        assert_eq!(lttb_indices(&xs, &ys, 1), vec![0]);
        assert_eq!(lttb_indices(&xs, &ys, 2), vec![0, n - 1]);
        // already within cap -> all indices unchanged
        assert_eq!(
            lttb_indices(&xs[..10], &ys[..10], 50),
            (0..10).collect::<Vec<_>>()
        );
    }

    /// A tight NYC cluster plus a handful of far-west bad coordinates, used to contrast the
    /// trimmed (`viz smart`) framing against the full-extent (`viz map`) framing.
    fn nyc_cluster_with_outliers() -> (Vec<f64>, Vec<f64>) {
        let mut lats = vec![40.7_f64; 200];
        let mut lons = vec![-73.95_f64; 200];
        // jitter so the cluster has a small but non-zero span
        for (i, (la, lo)) in lats.iter_mut().zip(lons.iter_mut()).enumerate() {
            *la += (i % 10) as f64 * 0.005;
            *lo += (i % 10) as f64 * 0.005;
        }
        // ~2.5% outliers dragging the raw bounding box out to Pennsylvania
        for _ in 0..5 {
            lats.push(40.5);
            lons.push(-77.5);
        }
        (lats, lons)
    }

    #[test]
    fn map_center_zoom_trimmed_ignores_outliers() {
        // robust (percentile-trimmed) framing must center on the cluster, not the outliers.
        let (lats, lons) = nyc_cluster_with_outliers();
        let (center, _zoom) = map_center_zoom(&lats, &lons, MAP_FRAME_TRIM_FRAC, 1000.0, 600.0);
        let lon = serde_json::to_value(&center).unwrap()["lon"]
            .as_f64()
            .unwrap();
        // raw min/max midpoint would be ~(-73.95 + -77.5)/2 = -75.7 (in Pennsylvania); the trimmed
        // framing must stay over the NYC cluster instead.
        assert!(
            lon > -74.3,
            "trimmed framing should not be pulled west of NYC, got lon {lon}"
        );
    }

    #[test]
    fn map_center_zoom_full_extent_includes_outliers() {
        // standalone `viz map` passes trim_frac == 0.0, so every coordinate frames the view; the
        // far-west outliers pull the center toward the raw midpoint (regression guard for the fix
        // that kept the trimming scoped to `viz smart`).
        let (lats, lons) = nyc_cluster_with_outliers();
        let (center, _zoom) = map_center_zoom(&lats, &lons, 0.0, 1000.0, 600.0);
        let lon = serde_json::to_value(&center).unwrap()["lon"]
            .as_f64()
            .unwrap();
        assert!(
            lon < -75.0,
            "full-extent framing must include the western outliers, got lon {lon}"
        );
    }

    #[test]
    fn auto_hierarchy_style_by_depth() {
        // best-practice rule: shallow (≤2 levels) → treemap, deep (3+ levels) → sunburst.
        assert_eq!(auto_hierarchy_style(2), HierStyle::Treemap);
        assert_eq!(auto_hierarchy_style(3), HierStyle::Sunburst);
        assert_eq!(auto_hierarchy_style(4), HierStyle::Sunburst);
    }

    #[test]
    fn wrap_kpi_label_wraps_on_word_boundaries() {
        // short labels stay on one line (no <br> injected), so exact-text consumers/tests still see
        // the whole label.
        assert_eq!(wrap_kpi_label("Completeness", 40), "Completeness");
        assert_eq!(
            wrap_kpi_label("Mean Customer Rating", 40),
            "Mean Customer Rating"
        );
        // a long label wraps at the last word boundary that fits within max_chars.
        assert_eq!(
            wrap_kpi_label("Mean Profit Margin Percentage", 20),
            "Mean Profit Margin<br>Percentage"
        );
        // a single word longer than max_chars is left intact rather than hard-split mid-word.
        assert_eq!(
            wrap_kpi_label("Supercalifragilistic", 8),
            "Supercalifragilistic"
        );
        // multiple wraps.
        assert_eq!(wrap_kpi_label("a b c d e", 3), "a b<br>c d<br>e");
    }

    #[test]
    fn resolve_hierarchy_style_flag() {
        assert_eq!(
            resolve_hierarchy_style(None, 2).unwrap(),
            HierStyle::Treemap
        );
        assert_eq!(
            resolve_hierarchy_style(Some("auto"), 3).unwrap(),
            HierStyle::Sunburst
        );
        // case-insensitive explicit override wins over the depth rule
        assert_eq!(
            resolve_hierarchy_style(Some("Treemap"), 3).unwrap(),
            HierStyle::Treemap
        );
        assert_eq!(
            resolve_hierarchy_style(Some("sunburst"), 2).unwrap(),
            HierStyle::Sunburst
        );
        // icicle is an explicit-only override (auto never picks it)
        assert_eq!(
            resolve_hierarchy_style(Some("icicle"), 3).unwrap(),
            HierStyle::Icicle
        );
        assert_eq!(
            resolve_hierarchy_style(Some("ICICLE"), 2).unwrap(),
            HierStyle::Icicle
        );
        assert!(resolve_hierarchy_style(Some("pie"), 2).is_err());
    }

    #[test]
    fn hierarchy_arrays_rolls_up_and_keeps_ids_unique() {
        // 2-level hierarchy; "Widgets"/"Gadgets" repeat under two regions to exercise id
        // uniqueness.
        let mut leaves: HashMap<Vec<String>, f64> = HashMap::new();
        leaves.insert(vec!["East".into(), "Widgets".into()], 150.0);
        leaves.insert(vec!["East".into(), "Gadgets".into()], 30.0);
        leaves.insert(vec!["West".into(), "Widgets".into()], 80.0);
        leaves.insert(vec!["West".into(), "Gadgets".into()], 20.0);
        leaves.insert(vec!["West".into(), "Gizmos".into()], 10.0);

        let (labels, parents, values, ids) =
            hierarchy_arrays(&leaves, 2, 12, 200, "All").expect("hierarchy");

        // synthetic root: parentless, labeled, value == grand total.
        assert_eq!(ids[0], HIER_ROOT_ID);
        assert_eq!(parents[0], "");
        assert_eq!(labels[0], "All");
        let total: f64 = leaves.values().sum();
        assert!((values[0] - total).abs() < 1e-9);

        // every non-root parent reference resolves to a real id.
        let id_set: std::collections::HashSet<&String> = ids.iter().collect();
        for (i, p) in parents.iter().enumerate().skip(1) {
            assert!(
                id_set.contains(p),
                "parent {p} of node {} not in ids",
                ids[i]
            );
        }
        // path-joined ids are unique despite repeated child labels.
        assert_eq!(id_set.len(), ids.len(), "ids must be unique");

        // a level-1 node's value == sum of its level-2 children (East = 150 + 30).
        let east_id = format!("{HIER_ROOT_ID}{HIER_PATH_SEP}East");
        let east_val = values[ids.iter().position(|x| *x == east_id).unwrap()];
        assert!((east_val - 180.0).abs() < 1e-9);
    }

    #[test]
    fn hierarchy_arrays_ids_survive_adversarial_segments() {
        // (a) a segment containing a literal HIER_PATH_SEP must not join-collide with the
        // equivalent split path; (b) a real child value equal to "<sentinel>other" must not
        // collide with the parent's Other-bucket id. All ids stay globally distinct and every
        // parent ref resolves.
        let mut leaves: HashMap<Vec<String>, f64> = HashMap::new();
        leaves.insert(vec![format!("A{HIER_PATH_SEP}B"), "x".to_string()], 10.0);
        leaves.insert(vec!["A".to_string(), "B".to_string()], 20.0);
        leaves.insert(
            vec!["A".to_string(), format!("{AGG_KEY_SENTINEL}other")],
            5.0,
        );
        leaves.insert(vec!["A".to_string(), "C".to_string()], 1.0);
        // top_n=2 under "A" forces an Other bucket alongside the literal "<sentinel>other" child
        let (labels, parents, values, ids) = hierarchy_arrays(&leaves, 2, 2, 100, "root").unwrap();
        assert_eq!(labels.len(), parents.len());
        assert_eq!(labels.len(), values.len());
        assert_eq!(labels.len(), ids.len());
        let distinct: std::collections::HashSet<&String> = ids.iter().collect();
        assert_eq!(
            distinct.len(),
            ids.len(),
            "ids must be globally unique: {ids:?}"
        );
        // every non-root parent reference resolves to an emitted id
        for p in parents.iter().skip(1) {
            assert!(ids.contains(p), "dangling parent ref {p:?}");
        }
    }

    #[test]
    fn hierarchy_arrays_folds_remainder_into_other() {
        // parent "R" has 4 children; top_n = 2 keeps a,b and folds c,d into "Other (2)".
        let mut leaves: HashMap<Vec<String>, f64> = HashMap::new();
        for (seg, v) in [("a", 40.0), ("b", 30.0), ("c", 20.0), ("d", 10.0)] {
            leaves.insert(vec!["R".into(), seg.into()], v);
        }
        // a second top-level category so the root itself splits (required for a real hierarchy).
        leaves.insert(vec!["S".into(), "x".into()], 5.0);

        let (labels, _parents, values, _ids) =
            hierarchy_arrays(&leaves, 2, 2, 200, "All").expect("hierarchy");

        let other_pos = labels
            .iter()
            .position(|l| l == "Other (2)")
            .expect("Other bucket");
        assert!((values[other_pos] - 30.0).abs() < 1e-9); // 20 + 10 dropped

        // kept children (40 + 30) + Other (30) == R's rolled-up value (100).
        let r_pos = labels.iter().position(|l| l == "R").unwrap();
        assert!((values[r_pos] - 100.0).abs() < 1e-9);
    }

    #[test]
    fn hierarchy_arrays_degenerate_returns_none() {
        // a single chain (no node splits into 2+) isn't worth a panel.
        let mut leaves: HashMap<Vec<String>, f64> = HashMap::new();
        leaves.insert(vec!["only".into(), "one".into()], 5.0);
        assert!(hierarchy_arrays(&leaves, 2, 12, 200, "All").is_none());
    }

    #[test]
    fn cramers_v_zero_for_independent_dims() {
        // Perfectly independent 2x2 joint (cell = row_tot*col_tot/n): chi-square is 0, so the
        // (bias-corrected) V is 0 — below HIER_MIN_ASSOCIATION_CRAMERS_V, so `viz smart` would
        // SKIP the hierarchy (this is exactly the sales_sample region/payment/category case).
        let mut leaves: HashMap<Vec<String>, f64> = HashMap::new();
        leaves.insert(vec!["a1".into(), "b1".into()], 30.0);
        leaves.insert(vec!["a1".into(), "b2".into()], 30.0);
        leaves.insert(vec!["a2".into(), "b1".into()], 20.0);
        leaves.insert(vec!["a2".into(), "b2".into()], 20.0);
        let v = max_pairwise_cramers_v(&leaves, 2);
        assert!(
            v < HIER_MIN_ASSOCIATION_CRAMERS_V,
            "independent V={v} should be ~0"
        );
    }

    #[test]
    fn cramers_v_high_for_nested_dims() {
        // Perfect nesting: each child category lives under exactly one parent (a real hierarchy),
        // so association is near-total and V clears the threshold — `viz smart` builds the panel.
        let mut leaves: HashMap<Vec<String>, f64> = HashMap::new();
        leaves.insert(vec!["a1".into(), "b1".into()], 25.0);
        leaves.insert(vec!["a1".into(), "b2".into()], 25.0);
        leaves.insert(vec!["a2".into(), "b3".into()], 25.0);
        leaves.insert(vec!["a2".into(), "b4".into()], 25.0);
        let v = max_pairwise_cramers_v(&leaves, 2);
        assert!(
            v >= HIER_MIN_ASSOCIATION_CRAMERS_V,
            "nested V={v} should be high"
        );
    }

    #[test]
    fn cramers_v_tiny_table_falls_back_to_uncorrected() {
        // 3x3 perfectly one-to-one table with only 3 rows: the Bergsma correction is undefined
        // (r_corr/c_corr collapse to 1.0, denom 0), but the dims ARE perfectly associated. The
        // uncorrected fallback must report a high V so this small hierarchy isn't wrongly skipped.
        let mut leaves: HashMap<Vec<String>, f64> = HashMap::new();
        leaves.insert(vec!["a1".into(), "b1".into()], 1.0);
        leaves.insert(vec!["a2".into(), "b2".into()], 1.0);
        leaves.insert(vec!["a3".into(), "b3".into()], 1.0);
        let v = max_pairwise_cramers_v(&leaves, 2);
        assert!(
            v >= HIER_MIN_ASSOCIATION_CRAMERS_V,
            "tiny perfectly-associated table V={v} should not read as independent"
        );
    }

    #[test]
    fn cramers_v_max_over_pairs_and_guards() {
        // fewer than two dims is undefined -> 0.0
        let mut single: HashMap<Vec<String>, f64> = HashMap::new();
        single.insert(vec!["x".into()], 10.0);
        assert_eq!(max_pairwise_cramers_v(&single, 1), 0.0);

        // 3 dims: levels 0&1 independent, but level 2 is perfectly nested under level 0; the MAX
        // over all pairs must surface that association so the panel isn't wrongly skipped.
        let mut leaves: HashMap<Vec<String>, f64> = HashMap::new();
        leaves.insert(vec!["a1".into(), "b1".into(), "c1".into()], 25.0);
        leaves.insert(vec!["a1".into(), "b2".into(), "c1".into()], 25.0);
        leaves.insert(vec!["a2".into(), "b1".into(), "c2".into()], 25.0);
        leaves.insert(vec!["a2".into(), "b2".into(), "c2".into()], 25.0);
        let v = max_pairwise_cramers_v(&leaves, 3);
        assert!(
            v >= HIER_MIN_ASSOCIATION_CRAMERS_V,
            "max-pair V={v} should catch nested level"
        );
    }

    #[test]
    fn sankey_concept_family_splits_on_dot() {
        assert_eq!(sankey_concept_family("geo.city"), Some("geo"));
        assert_eq!(sankey_concept_family("category.status"), Some("category"));
        assert_eq!(sankey_concept_family("nyc.complaint_type"), Some("nyc"));
        // no dot -> whole token is the family
        assert_eq!(sankey_concept_family("org"), Some("org"));
        // un-tagged columns yield no semantic signal
        assert_eq!(sankey_concept_family(""), None);
        assert_eq!(sankey_concept_family("  "), None);
        assert_eq!(sankey_concept_family("unknown"), None);
    }

    #[test]
    fn sankey_semantic_tier_ranks_bridges_over_geo_overlap() {
        // cross-family bridge (a real flow) -> preferred
        assert_eq!(
            sankey_semantic_tier("nyc.complaint_type", "category.status"),
            0
        );
        assert_eq!(sankey_semantic_tier("org.agency", "category.status"), 0);
        // both geo-context (spatial overlap) -> deprioritized
        assert_eq!(sankey_semantic_tier("geo.city", "geo.zip_code"), 2);
        // same family, or either side un-tagged -> neutral
        assert_eq!(sankey_semantic_tier("category.type", "category.status"), 1);
        assert_eq!(sankey_semantic_tier("", "category.status"), 1);
        assert_eq!(sankey_semantic_tier("unknown", "unknown"), 1);
    }

    #[test]
    fn sankey_side_topn_collapses_tail_into_other() {
        // more than SANKEY_TOP_N_PER_SIDE categories: the smallest collapse into "Other (k)".
        let mut tot: HashMap<String, f64> = HashMap::new();
        let n = SANKEY_TOP_N_PER_SIDE + 3;
        for i in 0..n {
            // descending weights so the last 3 are the collapsed tail
            tot.insert(format!("c{i:02}"), (n - i) as f64);
        }
        let (kept, kept_set, other, other_frac) = sankey_side_topn(&tot);
        assert_eq!(kept.len(), SANKEY_TOP_N_PER_SIDE);
        assert_eq!(kept_set.len(), SANKEY_TOP_N_PER_SIDE);
        assert_eq!(other.as_deref(), Some("Other (3)"));
        assert!(other_frac > 0.0 && other_frac < 1.0);
        // the heaviest category is kept and ordered first
        assert_eq!(kept[0], "c00");

        // at or below the cap: everything kept, no "Other".
        let mut small: HashMap<String, f64> = HashMap::new();
        small.insert("a".into(), 3.0);
        small.insert("b".into(), 1.0);
        let (kept, _set, other, other_frac) = sankey_side_topn(&small);
        assert_eq!(kept.len(), 2);
        assert_eq!(other, None);
        assert_eq!(other_frac, 0.0);
    }

    #[test]
    fn hex_to_rgba_parses_palette_hex() {
        // PALETTE[0] is #4C78A8 -> (76, 120, 168)
        assert_eq!(hex_to_rgba("#4C78A8", 0.45), "rgba(76,120,168,0.45)");
        // leading '#' is optional and lowercase hex parses too
        assert_eq!(hex_to_rgba("ff9da6", 0.5), "rgba(255,157,166,0.5)");
    }

    #[test]
    fn sankey_value_positions_ranks_by_flow_per_column() {
        // Bipartite: sources {0:A, 1:B}, targets {2:X, 3:Y}. A is the heavier source, X the
        // heavier target, so each should sit at the TOP (smaller y) of its column.
        //   A->X = 10, A->Y = 1, B->X = 2   (throughput: A=11, B=2, X=12, Y=1)
        let src = [0_usize, 0, 1];
        let tgt = [2_usize, 3, 2];
        let val = [10.0_f64, 1.0, 2.0];
        let (xs, ys) = sankey_value_positions(4, &src, &tgt, &val).unwrap();
        // source-only nodes hug the left, target-only nodes hug the right
        assert!(xs[0] < 0.5 && xs[1] < 0.5, "sources on the left");
        assert!(xs[2] > 0.5 && xs[3] > 0.5, "targets on the right");
        // within each column the heavier node is higher (smaller y)
        assert!(ys[0] < ys[1], "A (heavier source) above B");
        assert!(ys[2] < ys[3], "X (heavier target) above Y");
        // empty graph yields no positions
        assert!(sankey_value_positions(0, &[], &[], &[]).is_none());
    }

    #[test]
    fn pip_inside_outside_and_snap() {
        // one 0..10 square keyed by properties.id
        let gj = serde_json::json!({
            "type": "FeatureCollection",
            "features": [{
                "type": "Feature",
                "properties": {"id": "A"},
                "geometry": {"type": "Polygon", "coordinates":
                    [[[0.0, 0.0], [0.0, 10.0], [10.0, 10.0], [10.0, 0.0], [0.0, 0.0]]]}
            }]
        });
        let feats = build_pip_features(&gj, "properties.id", None).unwrap();
        assert_eq!(feats.len(), 1);
        assert_eq!(feats[0].id, "A");
        // (lat, lon) inside the square
        assert_eq!(
            pip_assign(&feats, 5.0, 5.0, false, f64::INFINITY),
            PipOutcome::Inside(0)
        );
        // far outside, no snap -> dropped
        assert_eq!(
            pip_assign(&feats, 50.0, 50.0, false, f64::INFINITY),
            PipOutcome::Outside
        );
        // far outside, snap with no distance cap -> nearest (the only) feature
        assert_eq!(
            pip_assign(&feats, 50.0, 50.0, true, f64::INFINITY),
            PipOutcome::Snapped(0)
        );
        // same point, but a tight cap is farther than any boundary -> dropped despite snap
        assert_eq!(
            pip_assign(&feats, 50.0, 50.0, true, 10.0),
            PipOutcome::Outside
        );
    }

    // the --snap-max-dist cap is an equirectangular km distance: a point ~5.6 km outside a region
    // snaps under a 10 km cap but drops under a 4 km cap (and always snaps when unbounded).
    #[test]
    fn pip_snap_distance_cap() {
        // unit square straddling the equator, where 1 degree ~ 111.32 km.
        let gj = serde_json::json!({
            "type": "FeatureCollection",
            "features": [{
                "type": "Feature",
                "properties": {"id": "A"},
                "geometry": {"type": "Polygon", "coordinates":
                    [[[0.0, 0.0], [0.0, 1.0], [1.0, 1.0], [1.0, 0.0], [0.0, 0.0]]]}
            }]
        });
        let feats = build_pip_features(&gj, "properties.id", None).unwrap();
        // 0.05 deg east of the boundary at the equator ~ 5.6 km out
        let (lat, lon) = (0.5, 1.05);
        assert_eq!(
            pip_assign(&feats, lat, lon, true, 10.0),
            PipOutcome::Snapped(0),
            "within the 10 km cap -> snaps"
        );
        assert_eq!(
            pip_assign(&feats, lat, lon, true, 4.0),
            PipOutcome::Outside,
            "beyond the 4 km cap -> dropped"
        );
        assert_eq!(
            pip_assign(&feats, lat, lon, true, f64::INFINITY),
            PipOutcome::Snapped(0),
            "unbounded cap always snaps"
        );
    }

    // the cap is an EQUIRECTANGULAR km distance: longitude degrees shrink by cos(lat). At lat 60.5,
    // a point 0.5 deg east of a boundary is ~27 km away (0.5 * 111.32 * cos(60.5) ~ 27.4) — NOT the
    // ~56 km a missing-cos(lat) bug would compute. The two-sided bracket (snaps under 35 km, drops
    // under 20 km) pins the longitude scaling: a no-cos bug would give 56 km and drop under 35.
    #[test]
    fn pip_snap_cap_applies_longitude_cos_scaling() {
        let gj = serde_json::json!({
            "type": "FeatureCollection",
            "features": [{
                "type": "Feature",
                "properties": {"id": "A"},
                "geometry": {"type": "Polygon", "coordinates":
                    [[[0.0, 60.0], [0.0, 61.0], [1.0, 61.0], [1.0, 60.0], [0.0, 60.0]]]}
            }]
        });
        let feats = build_pip_features(&gj, "properties.id", None).unwrap();
        // 0.5 deg east of the east edge at lat 60.5 -> ~27.4 km out
        let (lat, lon) = (60.5, 1.5);
        assert_eq!(
            pip_assign(&feats, lat, lon, true, 35.0),
            PipOutcome::Snapped(0),
            "~27 km < 35 km cap -> snaps (would be ~56 km and DROP without cos(lat) scaling)"
        );
        assert_eq!(
            pip_assign(&feats, lat, lon, true, 20.0),
            PipOutcome::Outside,
            "~27 km > 20 km cap -> dropped"
        );
    }

    // the `viz smart` GeoJSON choropleth panel honors the snap-distance cap: a point in the gap
    // between two regions (far from both) is dropped under the default cap — surfaced in the panel
    // title — but snapped when the cap is unbounded. Exercised at the unit level because the
    // dashboard's upstream geographic-column detection / outlier removal make an end-to-end fixture
    // brittle; this calls the panel builder directly with explicit coordinates.
    #[test]
    fn smart_pip_panel_caps_snap() {
        // two regions separated by a wide gap: A at lon 0..4, C at lon 16..20 (both lat 0..10).
        let gj = r#"{"type":"FeatureCollection","features":[
            {"type":"Feature","properties":{"id":"A"},"geometry":{"type":"Polygon",
             "coordinates":[[[0.0,0.0],[0.0,10.0],[4.0,10.0],[4.0,0.0],[0.0,0.0]]]}},
            {"type":"Feature","properties":{"id":"C"},"geometry":{"type":"Polygon",
             "coordinates":[[[16.0,0.0],[16.0,10.0],[20.0,10.0],[20.0,0.0],[16.0,0.0]]]}}]}"#;
        let path = std::env::temp_dir().join("qsv_smart_pip_cap_test.geojson");
        std::fs::write(&path, gj).unwrap();
        let spec = path.to_str().unwrap();
        // 2 points in A, 2 in C, 1 in the lon-10 gap (~6 deg / hundreds of km from either edge).
        let lats = vec![5.0, 4.0, 5.0, 4.0, 5.0];
        let lons = vec![2.0, 3.0, 18.0, 17.0, 10.0];

        // an explicit 10 km cap drops the gap point; the panel still renders (2 regions) and
        // flags the drop.
        let panel = build_smart_pip_choropleth_panel(
            spec,
            "properties.id",
            None,
            &lats,
            &lons,
            true,
            Some(10.0),
            None,
        )
        .unwrap()
        .expect("2 regions keep points, so a panel renders");
        assert_eq!(panel.name, "Regions (1 of 5 dropped, >10 km)");

        // an unbounded cap snaps the gap point instead -> nothing dropped; the title surfaces the
        // snap metadata (count + cap) rather than staying bare.
        let snapped = build_smart_pip_choropleth_panel(
            spec,
            "properties.id",
            None,
            &lats,
            &lons,
            true,
            Some(f64::INFINITY),
            None,
        )
        .unwrap()
        .expect("panel renders");
        assert!(
            snapped.name.starts_with("Regions (1 snapped"),
            "snapped points must surface in the title, got {:?}",
            snapped.name
        );

        // --no-snap drops the gap point regardless of distance; the title reports the reason.
        let no_snap = build_smart_pip_choropleth_panel(
            spec,
            "properties.id",
            None,
            &lats,
            &lons,
            false,
            Some(10.0),
            None,
        )
        .unwrap()
        .expect("panel renders");
        assert_eq!(no_snap.name, "Regions (1 of 5 dropped, --no-snap)");

        // the continental-extent regions above (20 deg lon / 10 deg lat span, both >=
        // SMART_CHOROPLETH_MIN_SPAN_DEG) stay on the projection `geo` basemap, NOT tiles.
        assert!(
            matches!(panel.kind, PanelKind::Choropleth { .. }),
            "continental extent uses the projection Choropleth, got {:?}",
            std::mem::discriminant(&panel.kind)
        );

        let _ = std::fs::remove_file(&path);
    }

    // a metro-scale `--geojson` choropleth (matched regions span < SMART_CHOROPLETH_MIN_SPAN_DEG in
    // BOTH dims) switches to the MapLibre tile basemap (`ChoroplethMap`), framed to the region
    // bbox, so city-scale coastline/street detail isn't lost on the coarse projection basemap.
    #[test]
    fn smart_pip_panel_metro_extent_uses_tile_basemap() {
        // two small adjacent NYC-scale regions: ~0.05 deg each, union ~0.1 deg lon / 0.05 deg lat.
        let gj = r#"{"type":"FeatureCollection","features":[
            {"type":"Feature","properties":{"id":"A"},"geometry":{"type":"Polygon",
             "coordinates":[[[-74.05,40.70],[-74.05,40.75],[-74.00,40.75],[-74.00,40.70],[-74.05,40.70]]]}},
            {"type":"Feature","properties":{"id":"B"},"geometry":{"type":"Polygon",
             "coordinates":[[[-74.00,40.70],[-74.00,40.75],[-73.95,40.75],[-73.95,40.70],[-74.00,40.70]]]}}]}"#;
        let path = std::env::temp_dir().join("qsv_smart_pip_metro_test.geojson");
        std::fs::write(&path, gj).unwrap();
        let spec = path.to_str().unwrap();
        // 2 points in A, 2 in B.
        let lats = vec![40.72, 40.73, 40.72, 40.73];
        let lons = vec![-74.02, -74.03, -73.97, -73.98];

        let panel = build_smart_pip_choropleth_panel(
            spec,
            "properties.id",
            None,
            &lats,
            &lons,
            true,
            Some(10.0),
            None,
        )
        .unwrap()
        .expect("2 regions keep points, so a panel renders");
        match panel.kind {
            PanelKind::ChoroplethMap {
                center_lon,
                center_lat,
                zoom,
                ..
            } => {
                // centered on the matched-region bbox union (lon -74.05..-73.95, lat 40.70..40.75).
                assert!(
                    (center_lon - (-74.0)).abs() < 1e-9,
                    "center_lon = {center_lon}"
                );
                assert!(
                    (center_lat - 40.725).abs() < 1e-9,
                    "center_lat = {center_lat}"
                );
                // a ~0.1 deg metro box zooms in well past the world view, within the fit clamp.
                assert!(
                    (9.0..=16.0).contains(&zoom),
                    "metro zoom should be street-level, got {zoom}"
                );
            },
            other => panic!(
                "metro extent should use the tile basemap, got {:?}",
                std::mem::discriminant(&other)
            ),
        }

        let _ = std::fs::remove_file(&path);
    }

    // as-written decimal counting for the command path's precision signal: exponent-aware,
    // trailing fractional zeros trimmed (matching the stats cache's shortest-format semantics).
    #[test]
    fn byte_decimal_places_counts() {
        assert_eq!(byte_decimal_places(b"12"), 0);
        assert_eq!(byte_decimal_places(b"-40.71"), 2);
        assert_eq!(byte_decimal_places(b"40.7100"), 2, "trailing zeros trimmed");
        assert_eq!(byte_decimal_places(b" 40.5 "), 1, "whitespace trimmed");
        assert_eq!(byte_decimal_places(b"1.5e-3"), 4, "0.0015 -> 4 decimals");
        assert_eq!(byte_decimal_places(b"7e-2"), 2, "0.07 -> 2 decimals");
        assert_eq!(byte_decimal_places(b"1.5E2"), 0, "150 -> 0 decimals");
        // trailing zeros must be trimmed AFTER the exponent is applied: a trailing-zero mantissa
        // cancels fractional positions of the shifted value (roborev #3488).
        assert_eq!(byte_decimal_places(b"150e-2"), 1, "1.5 -> 1 decimal");
        assert_eq!(byte_decimal_places(b"4070e-2"), 1, "40.7 -> 1 decimal");
        assert_eq!(byte_decimal_places(b"1000e-3"), 0, "1 -> 0 decimals");
        assert_eq!(byte_decimal_places(b"50.0e-1"), 0, "5 -> 0 decimals");
        assert_eq!(byte_decimal_places(b"0.150"), 2, "0.15 -> 2 decimals");
        // an all-zero mantissa is zero: 0 decimal places regardless of notation (roborev #3489).
        assert_eq!(byte_decimal_places(b"0e-3"), 0, "0 -> 0 decimals");
        assert_eq!(byte_decimal_places(b"0.0e-3"), 0, "0 -> 0 decimals");
        assert_eq!(byte_decimal_places(b"0.000"), 0, "0 -> 0 decimals");
        assert_eq!(byte_decimal_places(b""), 0);
        assert_eq!(byte_decimal_places(b"n/a"), 0);
    }

    /// Build PipFeatures from equator-anchored square boxes `side_deg` degrees on a side (one per
    /// `count`), for exercising the region-size term of the auto snap cap.
    fn square_features(side_deg: f64, count: usize) -> Vec<PipFeature> {
        let features: Vec<serde_json::Value> = (0..count)
            .map(|i| {
                // space the boxes apart so they don't merge visually; geometry only matters for
                // the bbox diagonal.
                let x0 = (i as f64) * (side_deg * 2.0);
                let (x1, y1) = (x0 + side_deg, side_deg);
                serde_json::json!({
                    "type": "Feature",
                    "properties": {"id": format!("R{i}")},
                    "geometry": {"type": "Polygon", "coordinates":
                        [[[x0, 0.0], [x0, y1], [x1, y1], [x1, 0.0], [x0, 0.0]]]}
                })
            })
            .collect();
        let gj = serde_json::json!({"type": "FeatureCollection", "features": features});
        build_pip_features(&gj, "properties.id", None).unwrap()
    }

    // ward-scale regions (~3 km bbox diagonal) with precise coordinates derive a sub-km cap from
    // the region-size term — the old fixed 10 km default would snap across several wards.
    #[test]
    fn snap_cap_ward_scale_region_fraction() {
        // 0.02 deg squares at the equator: diag = hypot(2.2264, 2.2264) ~ 3.149 km;
        // region term = 0.315 km; p=5 precision floor ~ 0.0016 km is negligible.
        let feats = square_features(0.02, 3);
        let cap = resolve_snap_cap(None, &feats, Some(5));
        assert!(
            (cap.km - 0.31).abs() < 1e-9,
            "ward-scale cap should be ~0.31 km, got {}",
            cap.km
        );
        assert!(matches!(
            cap.basis,
            SnapCapBasis::Auto {
                region_km:    Some(_),
                precision_km: Some(_),
            }
        ));
    }

    // country-scale regions clamp to the absolute ceiling instead of growing without bound.
    #[test]
    fn snap_cap_country_scale_clamps_max() {
        // 10 deg squares: diag ~ 1574 km -> region term ~ 157 km -> clamped to 100 km.
        let feats = square_features(10.0, 3);
        let cap = resolve_snap_cap(None, &feats, Some(4));
        assert!(
            (cap.km - SNAP_CAP_MAX_KM).abs() < f64::EPSILON,
            "continent-scale cap should clamp to {SNAP_CAP_MAX_KM}, got {}",
            cap.km
        );
    }

    // coarse coordinates dominate small regions: 1-decimal lat/lon quantizes by kilometers, so
    // the stats-aware precision floor (not the region term) sets the cap.
    #[test]
    fn snap_cap_precision_floor_dominates() {
        // region term ~ 0.315 km; p=1 floor = 2 * 111.32 * (1/sqrt(2)) * 0.1 ~ 15.74 -> 16 km.
        let feats = square_features(0.02, 3);
        let cap = resolve_snap_cap(None, &feats, Some(1));
        assert!(
            (cap.km - 16.0).abs() < 1e-9,
            "1-decimal coords should floor the cap at ~16 km, got {}",
            cap.km
        );
    }

    // with neither signal available the cap falls back to the fixed default.
    #[test]
    fn snap_cap_fallback_default() {
        let cap = resolve_snap_cap(None, &[], None);
        assert!((cap.km - DEFAULT_SNAP_MAX_KM).abs() < f64::EPSILON);
        assert_eq!(cap.basis, SnapCapBasis::Fallback);
    }

    // an explicit --snap-max-dist is used verbatim: no clamping, no 2-sig-fig rounding.
    #[test]
    fn snap_cap_explicit_wins() {
        let feats = square_features(0.02, 3);
        let cap = resolve_snap_cap(Some(3.456), &feats, Some(1));
        assert!((cap.km - 3.456).abs() < f64::EPSILON);
        assert_eq!(cap.basis, SnapCapBasis::Explicit);
    }

    // stats-cache coordinate precision: Float uses max_precision, Integer counts as 0 decimals,
    // and the coarser (min) column drives; anything else disables the floor.
    #[test]
    fn stats_coord_decimals_prefers_coarser_column() {
        use crate::cmd::stats::StatsData;
        let float_col = |p: Option<u32>| StatsData {
            r#type: "Float".to_string(),
            max_precision: p,
            ..Default::default()
        };
        let int_col = || StatsData {
            r#type: "Integer".to_string(),
            ..Default::default()
        };
        let string_col = || StatsData {
            r#type: "String".to_string(),
            ..Default::default()
        };

        let stats = vec![float_col(Some(5)), float_col(Some(2))];
        assert_eq!(stats_coord_decimals(&stats, 0, 1), Some(2));

        let stats = vec![float_col(Some(5)), int_col()];
        assert_eq!(
            stats_coord_decimals(&stats, 0, 1),
            Some(0),
            "an Integer coordinate column is 0-decimal"
        );

        let stats = vec![float_col(None), float_col(Some(2))];
        assert_eq!(
            stats_coord_decimals(&stats, 0, 1),
            None,
            "a stale cache without max_precision disables the floor"
        );

        let stats = vec![string_col(), float_col(Some(2))];
        assert_eq!(stats_coord_decimals(&stats, 0, 1), None);
    }

    #[test]
    fn pip_multipolygon_and_holes() {
        let gj = serde_json::json!({
            "type": "FeatureCollection",
            "features": [
                {"type": "Feature", "properties": {"id": "M"}, "geometry": {
                    "type": "MultiPolygon", "coordinates": [
                        [[[0.0, 0.0], [0.0, 2.0], [2.0, 2.0], [2.0, 0.0], [0.0, 0.0]]],
                        [[[10.0, 10.0], [10.0, 12.0], [12.0, 12.0], [12.0, 10.0], [10.0, 10.0]]]
                    ]}},
                {"type": "Feature", "properties": {"id": "H"}, "geometry": {
                    "type": "Polygon", "coordinates": [
                        [[20.0, 20.0], [20.0, 30.0], [30.0, 30.0], [30.0, 20.0], [20.0, 20.0]],
                        [[23.0, 23.0], [23.0, 27.0], [27.0, 27.0], [27.0, 23.0], [23.0, 23.0]]
                    ]}}
            ]
        });
        let feats = build_pip_features(&gj, "properties.id", None).unwrap();
        let m = feats.iter().position(|f| f.id == "M").unwrap();
        let h = feats.iter().position(|f| f.id == "H").unwrap();
        // inside the SECOND polygon of the MultiPolygon
        assert_eq!(
            pip_assign(&feats, 11.0, 11.0, false, f64::INFINITY),
            PipOutcome::Inside(m)
        );
        // inside H's filled band (between exterior and hole)
        assert_eq!(
            pip_assign(&feats, 21.0, 21.0, false, f64::INFINITY),
            PipOutcome::Inside(h)
        );
        // inside H's HOLE -> not contained; no snap -> dropped
        assert_eq!(
            pip_assign(&feats, 25.0, 25.0, false, f64::INFINITY),
            PipOutcome::Outside
        );
        // same hole point, snap with no cap -> snaps back to H (nearest boundary)
        assert_eq!(
            pip_assign(&feats, 25.0, 25.0, true, f64::INFINITY),
            PipOutcome::Snapped(h)
        );
    }

